INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989381","title":"Отряд Икс. Книга 2","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002808950/140/f0ef/Rik_Remender__Otryad_Iks._Kniga_2.jpg","isbn":"978-5-6040823-4-9,  978-5-6040823-6-2","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Росомаха. Псайлок. Архангел. Фантомекс. Дэдпул. Дэтлок. Вместе, они - Отряд Икс, команда мутантов с лицензией на убийство. Именно так они разобрались с Апокалипсисом, но в итоге столкнулись с ещё большей опасностью. Злодей отравил разум их напарника Архангела, и тот стал всемогущим и безумным Темным Ангелом. Теперь Отряду Икс предстоит сложный выбор, ведь уберечь мир от нового геноцида означает убить друга и возлюбленного. Но даже если они решается на такое, хватит ли у них сил? Также в книге: путешествие в опасный Иной Мир, встреча с корпусом Капитанов Британия и охота на злодеев из Эры Апокалипсиса!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":3.5,"review":"","added":9999233,"hdCover":""},{"id":"0989380","title":"Джокер","author":"Брайан Азарелло,Ли Бермехо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002326940/140/ea63/__Dzhoker.jpg","isbn":"978-5-389-12610-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Джокер выбрался из психушки, но ему, несмотря на улыбку, совсем не весело. За время его отсутствия бывшие подчиненные растащили хозяйский пирог до последней крошки, а самого Джокера списали со счетов, решив, что тот уже не вернется. Однако Джокер снова на свободе и пуще прежнего жаждет утопить Готэм в крови.  В долгих блужданиях по сумеркам души ему составят компанию такие персонажи, как Пингвин, Двуликий, Убийца Крок, Харли Квинн, Загадочник и, конечно же, Бэтмен… и да поможет им всем Господь.  История Джокера, рассказанная от лица его верного, хоть и наивного подручного по имени Джонни Фрост, — классический криминальный нуар, зубодробительный трип по городу среди залитых дождем улиц, грязного белья и сплошных разочарований.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":4,"review":"","added":9999232,"hdCover":""},{"id":"098937f","title":"Царство Небесное","author":"Марк Уэйд,Алекс Росс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002791481/140/4bd8/__Tsarstvo_Nebesnoe.jpg","isbn":"978-5-389-13325-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Царство Небесное» - легендарное, впечатляющее произведение, не потерявшее своей значимости с 1996 года, когда Марк Уэйд и Алекс Росс познакомили мир с этим шедевром комикс-индустрии. Впервые на русском языке!  Супергерои вездесущи, но героизм встречается все реже…  Десятилетиями решая самые острые проблемы Земли, члены Лиги Справедливости в конце концов отошли в тень. Однако пришедшее им на смену новое поколение борцов с преступностью вселяет в людей больше ужаса, нежели уверенности в завтрашнем дне. И снова будущее планеты оказывается под угрозой. Тогда Супермен, Чудо-Женщина и Бэтмен должны снова взяться за дело, чтобы в последней битве отстоять истину и справедливость!  Настоящее издание включает выпуски 1 - 4 и более сотни страниц набросков, эскизов, и разнообразных рабочих материалов, отражающих процесс создания одного из культовых комиксов DC.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":4,"review":"","added":9999231,"hdCover":""},{"id":"098937e","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 1. Восстание бэтменов","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785643/140/e950/Dzhejms_Tajnion_IV__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_1._V.jpg","isbn":"978-5-389-14319-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Жестоко избит профессиональный убийца, причем сделал это кто-то, прикрывшийся личиной Бэтмена. Оказавшись на месте преступления, Темный Рыцарь находит дрон, взломав который, понимает, что на плащеносцев Готэма началась охота. Противник силен, но что особенно удивительно – использует снаряжение Бэтмена и его тактику ведения боя. Мотивы нападающих не ясны, однако очевидно, что поодиночке герои Готэма с ними не справятся. Поэтому Бэтмен решает создать спецотряд во главе с Бэтвумен, призванный бороться с новой угрозой. Но смогут ли Брюс Уэйн и Кэтрин Кейн полностью положиться друг на друга? Ведь Брюс что-то скрывает, и совсем скоро Кэтрин узнает, что именно.  Отличная книга для новичков в мире DC! «Бэтмен: Detective Comics. Книга 1. Восстание бэтменов» – мощный триллер, созданный писателем Джеймсом Тайнионом IV («Бэтмен и Робин навсегда») и художниками Эдди Барроузом («Найтвинг») и Альваро Мартинесом («Люди Икс: Ultimate Comics»). Эта книга – метеорит на небосклоне DC. Включает выпуски №934–940.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":4,"review":"","added":9999230,"hdCover":""},{"id":"098937d","title":"Звёздные войны. Официальная коллекция комиксов. Выпуск № 2 - Классика. Часть 2","author":"Крис Клэрмонт,Арчи Гудвин,Арчи Гудвин, Крис Клэрмонт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002817772/140/7b98/__Zvjozdnye_vojny._Ofitsialnaya_kollektsiya_komiksov._Vypusk_No_2__Klassika._Cha.jpg","isbn":"","publisher":"DeAgostini","pubDate":"2018","language":"Русский","series":"Звёздные войны. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"После уничтожения «Звезды Смерти» Альянс повстанцев отправляет Люка Скайуокера на поиски места для главной базы. Его путешествие приведет к столкновениям с драконьими лордами, деспотичными правителями и даже с космическими пиратами. Потому что Империя – не единственное, чего стоит опасаться в Галактике! К счастью, наш герой всегда может рассчитывать на команду «Сокола Тысячелетия», принцессу Лею Органу и своих верных дроидов. Но достаточно ли будет их сил, чтобы выжить на «Колесе» – весьма негостеприимной космической станции?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":2.5,"review":"","added":9999229,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098937c","title":"Звёздные войны. Официальная коллекция комиксов. Выпуск № 1 - Классика. Часть 1","author":"Арчи Гудвин,Дональд Глут,Рой Томас,Говард Чайкин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002808521/140/4cb9/__Zvjozdnye_vojny._Ofitsialnaya_kollektsiya_komiksov._Vypusk_No_1__Klassika._Cha.jpg","isbn":"","publisher":"DeAgostini","pubDate":"2018","language":"Русский","series":"Звездные войны. Официальная коллекция комиксов","genres":[],"annotation":"Том 1. В сборник вошли выпуски серии «Звёздные войны» (1977-1978) #1-11.  Эта наиболее полная коллекция комиксов о Легендарной Вселенной включает в себя лучшие истории, созданные более, чем за 40 лет существования Космической саги — начиная с первых комиксов, опубликованных в 1977 году, заканчивая работами последних лет. Многие из комиксов коллекции будут опубликованы в России впервые. В коллекции представлены такие легендарные серии, как Империя, Тёмные времена, Войны клонов, Восстание, Наследие и многие другие. Коллекция в том числе включает уникальные истории, которые никогда не появлялись в фильмах. Корешки книг образуют рисунок с героями саги. 200 страниц красочных комиксов в твёрдом переплёте в каждом выпуске (среднее количество страниц).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":2.5,"review":"","added":9999228,"hdCover":""},{"id":"098937b","title":"Академия Амбрелла (сборник)","author":"Джерард Уэй,Габриэль Ба","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003000006/140/1ff5/__Akademiya_Ambrella_sbornik.jpg","isbn":"978-5-04-101982-2","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Академия Амбрелла. Black Edition Более двадцати лет назад на свет появились сорок три необыкновенных ребёнка. Семеро из них выжили и были усыновлены сэром Реджинальдом Харгривзом. Пройдут годы, и они станут знаменитой Академией Амбрелла, невероятной командой с суперспособностями, чьё призвание - спасти весь мир. Однако эта история не о их детстве, а о том, что случилось потом, гораздо позже. Знаменитый экс-солист группы My Chemical Romance Джерард Уэй и бразильский художник комиксов Габриэль Ба (Daytripper, Casanova, De:TALES) расскажут нам не просто ещё одну историю спасения мира супергероями. Во-первых, это совершенно удивительные и уникальные супергерои, а во-вторых, акцент в этой книге делается на их взаимоотношениях и внутренних переживаниях, вопросах совести и жизненной цели, а не на умении летать или драться с роботами-убийцами. В данное издание вошли две книги: \"Академия Амбрелла: Сюита Апокалипсиса\" и \"Академия Амбрелла: Даллас\". Вторая книга намного круче первой, но без первой вы ни за что не поймёте, почему вторая такая классная. А впрочем… они обе потрясающие, здесь есть всё: зомби-робот Гюстав Эйфель, гигантская ожившая статуя Авраама Линкольна, убийственная музыка, самые опасные убийцы за все времена, которые носят мультяшные маски и обожают печенье от девочек-скаутов. И ещё, конечно же, будет уничтожен мир. Звучит захватывающе? Тогда эта книга для вас. Кстати, ещё она получила кучу премий, в том числе и премию Айснера за лучшую мини-серию.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":3,"review":"","added":9999227,"hdCover":""},{"id":"098937a","title":"Удивительный Человек-Паук. Гражданская Война","author":"Дж. Майкл Стражински","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002869818/140/1790/Dzh._Majkl_Strazhinski__Udivitelnyj_ChelovekPauk._Grazhdanskaya_Vojna.jpg","isbn":"978-5-04-097441-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь Питера Паркера ещё никогда не была такой запутанной… и опасной. Прибыв в Стэмфорд на место трагедии, дабы оказать помощь жертвам, Питер неожиданно отправляется с Тони Старком в Вашингтон. Там в Белом доме и будет неминуемо принят Акт о регистрации сверхлюдей. Пока вселенная Marvel готовится к вступлению в силу закона, что навсегда изменит общественный статус супергероев, Питер вынужден сделать личный и очень важный выбор... возможно, самый важный в его жизни. Гражданская Война поделила супергеройское общество на два лагеря, но останется ли Паучок верен своему решению?  В сборник вошли комиксы \"Удивительный Человек Паук\" #532-538, написанные Дж. Майклом Стражински и проиллюстрированные Роном Гарни.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":2.5,"review":"","added":9999226,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989379","title":"Хранители. Начало: Ночная Сова. Доктор Манхэттен. Озимандия (сборник)","author":"Джей Майкл Стражински,Лен Уэйн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002112590/140/b4e4/__Hraniteli._Nachalo_Nochnaya_Sova._Doktor_Manhetten._Ozimandiya_sbornik.jpg","isbn":"978-5-389-09807-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Серия долгожданных приквелов к одному из величайших графических романов всех времен «Хранители» наконец перед вами!  В течение более чем двадцати лет предыстории культовых персонажей Алана Мура и Дэйва Гиббонса оставались загадкой. До сих пор. Но DC Comics собрал команду самых выдающихся творцов в индустрии, которые смогли развернуть мир «Хранителей», протянув в прошлое истории наиболее противоречивых антигероев из когда-либо действовавших на страницах комиксов.  Какой путь прошел Адриан Вейдт, будущий Озимандия, чтобы стать умнейшим человеком на Земле? Кого убрал с этого пути? Какую цену заплатил? На какие жертвы обрек человечество и самого себя? Перед нами бескомпромиссный портрет человека, чье бескорыстное желание спасти испорченную планету было оплачено потерей человечности.  Героем Дэна Драйберга был Ночная Сова — упорный защитник справедливости и воплощение честности. Отчаянное желание сбежать из неблагополучного дома приводит Дэна в дом его кумира — Холлиса Мейсона, человека, скрывающегося под маской Ночной Совы. Впечатлив Мейсона технической смекалкой, Дэн принимает от него эстафету борца с преступностью.  Джон Остерман — педантичный и добросовестный ученый, который в результате страшного несчастного случая при проведении эксперимента, превратился в расщепляющего атом Доктора Манхэттена. Бывший ученый скользит во времени сквозь прошлое, настоящее и будущее. Свободный от всех земных оков, он наблюдает за временными потоками того, что уже произошло, могло произойти и еще только может. Наделенный почти божественными силами и способностью менять мир малейшим движением Доктор Манхэттен сражается за последние капли своей ускользающей человечности.  Безжалостный гений Озимандия, непостижимый Доктор Манхэттен, летящий во тьме Ночная Сова – на страницах второго сборника. Лен Уэйн и Майкл Стражински создали великолепный бэкграунд, подарив классическим образам новую жизнь, а блистательная команда художников в лице Джэ Ли, Энди Кьюберта, Джо Кьюберта, Билла Сенкевича, Адама Хьюза и других, заставили эти образы заиграть новыми красками.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-02","rating":4,"review":"","added":9999225,"hdCover":""},{"id":"0989378","title":"Вселенная DC. Rebirth. Зеленая Стрела. Книга 1: Смерть и жизнь Оливера Квина (сборник)","author":"Бенджамин Перси","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002827756/140/f931/Bendzhamin_Persi__Vselennaya_DC._Rebirth._Zelenaya_Strela._Kniga_1_Smert_i_zhizn.jpg","isbn":"978-5-389-14439-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Репутация Оливера Квина – избалованного миллиардера из Сиэтла, руководителя компании «Квин Индастриз» – оставляет желать лучшего. Но мало кто знает, каков он на самом деле. Ведь по ночам Оливер перевоплощается в Зеленую Стрелу, невозмутимого борца за справедливость, патрулирующего улицы Сиэтла.  И Стреле есть чем заняться – в городе начали пропадать бездомные. Десятки исчезнувших в неизвестном направлении женщин и детей. Кому они нужны и кто считает себя вправе безнаказанно творить зло прямо под носом у полиции? Затеяв свое расследование, Квин выясняет, что не все, кому он доверял, были честны с ним. Подняться с колен, когда тебя предают самые близкие, способен не каждый. Сможет ли Зеленая Стрела найти в себе силы, чтобы разрушить преступный сговор и вернуть обратно свою жизнь?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":4,"review":"","added":9999224,"hdCover":""},{"id":"0989377","title":"Вселенная DC. Rebirth. Лига Справедливости. Книга 2. Заражение","author":"Брайан Хитч","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002842647/140/1033/Brajan_Hitch__Vselennaya_DC._Rebirth._Liga_Spravedlivosti._Kniga_2._Zarazhenie.jpg","isbn":"978-5-389-14591-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"После того как состав Лиги Справедливости пополнили Супермен из другого мира и двое молодых и энергичных Зеленых Фонарей, команда стала сильнее, крепче, и перед ней открылись новые перспективы. Никогда еще она не была такой сплоченной, и кажется, теперь ни одному злодею не выстоять перед мощью лучших в мире супергероев.  Но что делать, если враг неосязаем? Если он – компьютерный код, который может обрушить спутник Лиги, взять под контроль Киборга и взломать Кольцо Зеленого Фонаря? Смогут ли герои отследить неуловимый вирус, способный проникнуть в любую систему, и найти его создателя прежде, чем пострадают невинные люди?  Ответы на все эти вопросы ждут вас в сборнике «ЛИГА СПРАВЕДЛИВОСТИ. КНИГА 2. ЗАРАЖЕНИЕ», в котором сценарист БРАЙАН ХИТЧ («ЛИГА СПРАВЕДЛИВОСТИ АМЕРИКИ») и художники НИЛ ЭДВАРДС («ТЕМНЫЕ МСТИТЕЛИ») и ДЭНИЕЛ ЭНРИКЕС («ЛИГА СПРАВЕДЛИВОСТИ АМЕРИКИ») продолжают сагу о главной команде супергероев комиксов. Под этой обложкой собраны выпуски «ЛИГИ СПРАВЕДЛИВОСТИ» #6-11.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":2,"review":"","added":9999223,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989376","title":"Вселенная DC. Rebirth. Лига Справедливости. Книга 1. Машины Уничтожения (сборник)","author":"Брайан Хитч","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785607/140/264c/Brajan_Hitch__Vselennaya_DC._Rebirth._Liga_Spravedlivosti._Kniga_1._Mashiny_Unic.jpg","isbn":"978-5-389-14447-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Они — величайшие герои в истории нашей планеты. Но самого великого из них больше нет.  Супермен погиб. Человек из Стали отдал свою жизнь, защищая мир, который стал для него родным, и теперь его друзьям придется сражаться без него. Но упавшее знамя подхватил другой Супермен, пришедший к нам из иной, погибшей вселенной.  Впрочем, Бэтмен, Чудо-Женщина, да и другие члены Лиги не спешат признавать его своим союзником. Новому Супермену придется многое доказать. Причем доказать очень скоро. Ведь Землю атакует противник, чье могущество невозможно измерить. И вот-вот придут в действие исполинские механизмы, которые изуродуют поверхность нашей планеты и превратят ее обитателей в живое оружие.  Машины Уничтожения. Чтобы их отключить, потребуются совместные усилия всех членов Лиги Справедливости. Всех до единого.  Суперзвезды комикс-индустрии Брайан Хитч («Лига Справедливости Америки») и Тони С. Дэниел («Супермен/Чудо-Женщина») объединили свои усилия, прокладывая величайшей команде супергероев дорогу в новую эру. «Лига Справедливости. Книга 1. Машины Уничтожения» — настоящий фейерверк среди событий DC Rebirth! В сборник вошли выпуски 1-5 «Лиги Справедливости», а также одиночный выпуск «Лига Справедливости: Rebirth».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":2,"review":"","added":9999222,"hdCover":""},{"id":"0989375","title":"Веном. Том 2","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002796114/140/7e08/Rik_Remender__Venom._Tom_2.jpg","isbn":"978-5-91878-253-8","publisher":"Фантастика Книжный Клуб","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Посреди Лас-Вегаса открывается портал в Преисподнюю, и теперь Веном должен объединиться с Красным Халком, Икс-23 и Призрачным Гонщиком, чтобы вместе с ними остановить распространение Ада на Земле. Удастся ли четырём небезупречным героям одолеть своих внутренних демонов и сплотиться ради спасения мира в самый тёмный час? Впереди Венома ждёт череда опаснейших испытаний: Преступный Гений, желая уничтожить его, сколотил банду из Джека-Фонарщика, Человека-Мухи, Токсина и других злодеев! Следуя дьявольскому плану вожака, они объявляют семье и друзьям Флэша Томпсона войну, в которой не обойдётся без жертв! Тем временем Веном присоединяется к Тайным Мстителям, но сколько в нём осталось от самого Флэша? Хоть симбиот под контролем, мрачные секреты Томпсона всё же могут погубить его — особенно после возвращения прежнего носителя Венома, Эдди Брока!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":3.5,"review":"","added":9999221,"hdCover":""},{"id":"0989374","title":"Веном. Том 1","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002072044/140/a511/Rik_Remender__Venom._Tom_1.jpg","isbn":"978-5-91878-177-7","publisher":"Фантастика Книжный Клуб","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Флэш Томпсон — в прошлом задира, а ныне верный друг Питера Паркера — самый большой фанат Человека-Паука. Именно кумир вдохновил его вступить добровольцем в ряды армии США, где он стал героем войны и ветераном, награждённым знаками отличия. Несмотря на утрату ног, Флэш никогда не терял достоинства и желания продолжать службу. Теперь правительство предложило ему шанс стать героем ещё раз, но для этого Томпсону придётся примерить необычный костюм — инопланетного симбиота. Создание-паразит не только даёт своему носителю силы, как у Человека-Паука, но и подвергает опасности полного соединения с собой. Флэш Томпсон — это Веном, смертоносный оперативник правительства, которого посылают в горячие точки против опаснейших врагов государства. Герой и раньше преодолевал трудности, но на этот раз его сильнейшим соперником может оказаться он сам.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":4,"review":"","added":9999220,"hdCover":""},{"id":"0989373","title":"Веном. Полное собрание","author":"Дэниел Уэй","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002948886/140/f2c1/Deniel_Uej__Venom._Polnoe_sobranie.jpg","isbn":"978-5-91878-307-8","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Инопланетный симбиот Веном, одаряющий человека-носителя смертельными сверхспособностями, сливается с людьми, испытывающими сильные низменные эмоции: ярость, ревность и ненависть. Именно они его привлекают. Отделённый от Эдди Брока, заклятый враг Человека-Паука объявляется рядом с полярным кругом — с лёгкостью перепрыгивая с носителя на носителя, он бежит от загадочных сил, имеющих собственные планы на неуловимого пришельца. Пытаясь утолить зверский голод и жажду адреналина, Веном прокладывает кровавую просеку на пути к цивилизации. В северных областях Канады он обращает внимание на невысокого заросшего парня с дурным характером: Росомаху из Людей Икс! А когда место действия переносится в Нью-Йорк, Человек-Паук и Фантастическая четвёрка вынуждены ликвидировать последствия разрушений, вызванных ДВУМЯ кровожадными веномоподобными существами! И входит Эдди Брок! Издание содержит выпуски «Венома» № 1–18, написанные Дэниелом Уэем, иллюстрированные Франсиско Эррерой, Пако Мединой, Шоном Гэллоуэем и Скотти Янгом..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":3.5,"review":"","added":9999219,"hdCover":""},{"id":"0989372","title":"Громовержцы. Полная коллекция","author":"Уоррен Эллис,Майк Деодато","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002541906/140/fd99/__Gromoverzhtsy._Polnaya_kollektsiya.jpg","isbn":"978-5-9909878-2-1","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Громовержцы — команда бывших злодеев, вставших на сторону добра. Они изо всех сил старались заработать доверие публики… но так и не приблизились к своей цели — признание не пришло. Однако после событий Гражданской войны всё изменилось: пора Америке познать силу настоящего правосудия! Страна утратила веру в героев. Теперь она готова поверить в чудовищ. Настал час Громовержцев!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":4,"review":"","added":9999218,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989371","title":"Лига Справедливости. Книга 6. Война Дарксайда. Часть 1","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002688008/140/36d1/Dzheff_Dzhons__Liga_Spravedlivosti._Kniga_6._Vojna_Darksajda._Chast_1.jpg","isbn":"978-5-389-13723-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Несколько лет назад супергерои создали Лигу Справедливости для борьбы с Дарксайдом и его армией парадемонов. Тогда совместными усилиями им удалось остановить злодея, и Земля была спасена. И вот Дарксайд вновь оказывается на нашей планете, которой суждено стать полем боя с Анти-Монитором – самым разрушительным существом во всей Мультивселенной.  Чудо-Женщина, Супермен, Бэтмен и остальные участники Лиги вместе с Мистером Чудо пытаются предотвратить грядущее сражение. Но когда в битве, результатом которой может стать исчезновение всего сущего, сходятся два воплощения абсолютного зла, даже лучшие из лучших могут оказаться бессильными.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":5,"review":"","added":9999217,"hdCover":""},{"id":"0989370","title":"Арчи. Том 6","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003165064/140/6772/Mark_Uejd__Archi._Tom_6.jpg","isbn":"978-5-04-105955-2","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Приближается важнейшее событие в жизни школьников Ривердейла – весенние танцы! А поскольку в городе распались почти все пары, главная интрига заключается в том, кто с кем придёт! Танцы обещают кучу сюрпризов: ребята встречаются и расстаются, Арчи снова играет на гитаре, на сцену выходят \"Джози и Кошечки\", Реджи вынашивает очередной зловредный план, а Би готовится сообщить всем важное известие – но никто и не представляет, что будет дальше! Раскрылась тайна семьи Блоссомов – и она удивит весь Ривердейл, в том числе и Шерил с Джейсоном! Ведь их настоящий отец возвращается, чтобы отомстить. И вернётся он именно в день танцев. Этот роковой вечер станет для всех испытанием! Школьники Ривердейла окажутся в заложниках у отца Блоссомов! Реджи заплатит за свои злодеяния! А когда вам покажется, что всё позади, Ривердейл снова встанет на уши!  В этой книге собраны последние комиксы исторического рана Марка Уэйда на обновлённой серии \"Арчи\". В книгу вошли выпуски \"АРЧИ\" #28–32 от сценаристов МАРКА УЭЙДА (\"Царство небесное\",, \"Чёрная Вдова\") и ИЭНА ФЛИННА (\"Джагхед\", \"Могучие Крестоносцы\") и художницы ОДРИ МОК (\"Джози и Кошечки\", Heroine Chic).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999216,"hdCover":""},{"id":"098936f","title":"Арчи. Том 5","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003165062/140/88a5/Mark_Uejd__Archi._Tom_5.jpg","isbn":"978-5-04-105952-1","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Бетти Купер – не просто добросердечная девчушка из соседнего двора. Она – душа Ривердейла. Почему? Узнаете в пятом сборнике признанных и любимых комиксов об Арчи! Ривердейл неспокоен: из-за автокатастрофы всеобщая любимица Бетти Купер оказалась в инвалидном кресле. Город пытается оправиться от потрясения, но все прекрасно понимают, что ничего уже не будет как прежде. Бетти изо всех сил старается вновь встать на ноги, а Реджи Мэнтл теперь изгой, ведь именно его все винят в случившемся. Непростая ситуация раскрывает Бетти глаза: она видит, насколько благородны и добродушны её друзья... а Арчи всё сильнее в неё влюбляется! Но как же Вероника? Дружба и отношения теперь под ударом, судьбы летят под откос, целые семьи рвут связи друг с другом, и только школьники Ривердейла могут спасти город от кризиса.  \"Душа Ривердейла\" – это трогательный сюжет о подлинном смысле дружбы. В пятый том \"Арчи\" вошли выпуски 25–27 от звёздного сценариста МАРКА УЭЙДА (\"Царство небесное\", \"Чёрная Вдова\") и художницы ОДРИ МОК (\"Джози и кошечки\", Heroine Chic).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999215,"hdCover":""},{"id":"098936e","title":"Арчи. Том 4","author":"Марк Уэйд,Пит Вудс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002927863/140/8d11/__Archi._Tom_4.jpg","isbn":"978-5-04-100547-4","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь Арчи и его лучших друзей изменится навсегда на страницах книги «Под откос», четвёртого сборника обласканного критиками комикс-бестселлера «Арчи». Это один из самых обсуждаемых комиксов последних лет!  Борьба Арчи с его заклятым врагом Реджи Мэнтлом достигает пика: они устраивают гонку, чтобы определить, кто из них настоящий король Ривердейла. Но они понятия не имеют, что в дело вмешается подруга и бывшая девушка Арчи Бетти Купер – и это приведёт к катастрофическим последствиям. Уцелеет ли один из героев в неожиданной схватке со смертью?  Берущая за душу и обладающая всеми характерными для последних комиксов об Арчи история «Под откос» раскрывает истинную природу отношений культовых персонажей. Читатели испытают чувство утраты и узнают, что такое настоящая дружба.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999214,"hdCover":""},{"id":"098936d","title":"Арчи. Том 2","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002721827/140/15db/Mark_Uejd__Archi._Tom_2.jpg","isbn":"978-5-91339-576-4","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ПРИКЛЮЧЕНИЯ НОВОГО АРЧИ ПРОДОЛЖАЮТСЯ!  Любимый рыжий герой Америки возвращается в очередном томе новой увлекательной серии «Арчи».  Богатая и неприступная Вероника Лодж привела в Ривердейл бурю… в результате которой всем нужно выбрать сторону, а Арчи Эндрюс застрял в самом эпицентре. От школьного романа до политических интриг, такого Арчи вы ещё не видели!  Суперзвезда серии, автор МАРК УЭЙД объединился с восходящей звездой, художницей ВЕРОНИКОЙ ФИШ, и новыми коллегами в лице ТОМАСА ПИТИЛЛИ и РАЙАНА ДЖЕМПОЛА, чтобы представить современный взгляд на легендарных жителей Ривердейла.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999213,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098936c","title":"Арчи. Том 1","author":"Фиона Стэплз,Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001889110/140/32de/__Archi._Tom_1.jpg","isbn":"978-5-91339-415-6","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Добро пожаловать в новый Ривердейл! Арчи Эндрюс, любимый подросток Америки, перерождается на страницах этого потрясающего сборника первых шести выпусков легендарной серии комиксов.  Встречайте Арчи, ученика средней школы Ривердейла, его чудаковатого друга-обжору Джагхеда, соседскую девчонку Бетти и состоятельную выскочку Веронику Лодж в перезапуске всеми любимого мира «Арчи». Здесь есть всё: любовный треугольник, дружба, юмор, очарование и море веселья в современном ключе.  Над комиксом работали настоящие мастера жанра: сценарист Марк Уэйд («Сорвиголова») и знаменитые художницы: Фиона Стэплз («Сага»), Энни Ву и Вероника Фиш. В первом томе «Арчи» читателей ждёт новый подход к полюбившейся многим концепции «Арчи Комикс», в котором нашлось место всему лучшему из 75-летней истории издательства.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999212,"hdCover":""},{"id":"098936b","title":"Injustice: Боги среди нас. Год второй. Книга 2","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002730435/140/3045/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_vtoroj._Kniga_2.jpg","isbn":"978-5-389-14112-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Грядет война между героями, которые некогда были друзьями. Война богов. У сурового диктатора Супермена появляется новый союзник — наводящий ужас Корпус Синестро. Стражи Вселенной не рады действиям Супермена и отправляют Корпус Зеленых Фонарей на помощь альянсу героев, выступивших против его несправедливого режима. Все, от самой грандиозной космической силы до крохотной зеленой пули, будет пущено в ход против обезумевшего бога. Но смерть — не единственный способ остановить его.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":4.5,"review":"","added":9999211,"hdCover":""},{"id":"098936a","title":"Вселенная DC. Rebirth. Лига Справедливости против Отряда Самоубийц","author":"Роб Уильямс,Джошуа Уильямсон,Тим Сили","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002950885/140/7a18/__Vselennaya_DC._Rebirth._Liga_Spravedlivosti_protiv_Otryada_Samoubijts.jpg","isbn":"978-5-389-15251-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Самые могущественные супергерои Земли из Лиги Справедливости неустанно сражаются со злодеями, оберегая покой мирных жителей. Но как быть, когда ради дела нужно поступиться моральными принципами? Пригласить Отряд Самоубийц – секретную Опергруппу Икс, действующую под руководством Аманды Уоллер? Ее бойцы не стесняются в выборе средств во имя достижения поставленных целей. И все бы ничего, если бы не Бэтмен.  Темный Рыцарь ни за что не потерпит существования организации подобного рода, и Лига Справедливости его в этом поддержит. Но, пока Лига и Отряд заняты борьбой друг с другом, преступный гений-телепат Максвелл Лорд собирает армию непобедимых злодеев, чтобы с их помощью завладеть опаснейшим оружием и получить полный контроль над миром!  Этот остросюжетный кроссовер с участием величайших героев и злодеев в истории DC создан звездной командой авторов, включающей писателей Джошуа Уильямсона, Тима Сили, Роба Уильямса и Сая Спурье, крупнейших художников Джейсона Фейбока, Тони С. Дэниела, Хесуса Мерино, Фернандо Пасарина, Робсона Роша, Говарда Портера, Скота Итона, Райли Россмо, Кристиана Дусэ и Джузеппе Кафаро.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999210,"hdCover":""},{"id":"0989369","title":"Дэдпул MAX. Полное издание","author":"Дэвид Лэпхем,Шон Кристал,Кайл Бейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002946167/140/8ee1/__Dedpul_MAX._Polnoe_izdanie.jpg","isbn":"978-5-04-099065-8","publisher":"Эксмо, Комильфо","pubDate":"2019","language":"Русский","series":"Дэдпул. Полные издания","genres":["Комиксы","манга","графические романы"],"annotation":"Суди психа по делам его!  Уэйд Уилсон — самый опасный и ценный наёмник, работающий на Дядю Сэма. но ему, как, например, автомату Калашникова, нужна рука, которая не позволит ему бить мимо цели. Следить за тем, чтобы Дэдпул выполнял порученные ему задания во что бы то ни стало, — работа Боба. Но помимо этого, именно ему приходится ещё и получать за двоих — его сломанные кости и психологические травмы тому доказательство.  Этот психопатический дуэт становится на путь саморазрушения, попутно уничтожая бандитов, террористов, правительство, шлюшек с пушками, собственное жуткое прошлое и своих возлюбленных. И всё это ради борьбы за свободу, во время которой им придётся столкнуться со всем ужасом, накопившимся в их собственных душах.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3,"review":"","added":9999209,"hdCover":""},{"id":"0989368","title":"Мстители","author":"Джордж Перес,Курт Бьюсик, Алекс Росс","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002950979/140/51ef/__Mstiteli.jpg","isbn":"9772619134209-002","publisher":"Hachette","pubDate":"2019","language":"Русский","series":"Супергерои Марвел. Официальная коллекция.","genres":["Детские книги"],"annotation":"Когда начинаются новые, смутные времена, а со злодеями, угрожающими человечеству, уже не справиться в одиночку, величайшие герои Вселенной Marvel объединяются в непобедимую боевую команду Мстителей. В этом выпуске вы узнаете о том, как команда впервые собралась для битвы с богом Локи, а также станете свидетелями одного из самых масштабных сражений команды с суперзлодеем-металоманьяком Альтроном и полчищами его роботов-копий.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3,"review":"","added":9999208,"hdCover":""}]');
